                    <a href="tel:+6567441123" className="block text-2xl md:text-3xl hover:opacity-70 transition-opacity mb-2">+65 67441123</a>
                    <a href="mailto:hello@orfeoai.com" className="block text-2xl md:text-3xl hover:opacity-70 transition-opacity">hello@orfeoai.com</a>
