import React from 'react';

interface ButtonProps {
  text: string;
  href: string;
  variant?: 'solid' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  icon?: React.ReactNode;
  className?: string;
}

export default function Button({ text, href, variant = 'solid', size = 'md', icon, className = '' }: ButtonProps) {
  const baseClasses = "group relative inline-flex items-center justify-center rounded-full transition-all duration-300 font-medium tracking-wider uppercase";

  const sizeClasses = {
    sm: "px-5 py-2 text-xs",
    md: "px-8 py-4 text-sm",
    lg: "px-10 py-5 text-base"
  };

  const variantClasses = {
    solid: "bg-[#d4cee4] text-[#0d0a16] hover:bg-white border border-transparent",
    outline: "bg-transparent text-white border border-white/30 hover:border-white hover:bg-white/5 backdrop-blur-sm"
  };

  return (
    <a 
      href={href} 
      className={`${baseClasses} ${sizeClasses[size]} ${variantClasses[variant]} ${className}`}
    >
      <span className="relative z-10 flex items-center gap-3">
        {text}
        {icon && <span className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform duration-300">{icon}</span>}
      </span>
    </a>
  );
}

import React from 'react';

interface SectionProps {
  children: React.ReactNode;
