import React, { useEffect, useState } from 'react';
import { ArrowUpRight } from 'lucide-react';
import Button from './Button';

export default function Hero() {
  const [opacity, setOpacity] = useState(1);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPosition = window.scrollY;
      const fadeStart = 0;
      const fadeEnd = 300; // Pixels to fully fade out

      let newOpacity = 1 - (scrollPosition - fadeStart) / (fadeEnd - fadeStart);
      newOpacity = Math.min(Math.max(newOpacity, 0), 1);

      setOpacity(newOpacity);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="relative min-h-screen w-full flex items-center justify-center overflow-hidden bg-[#0F0F12]">
      {/* Video Background with Heavy Overlay */}
      <div className="absolute inset-0 w-full h-full z-0">
        <video 
          autoPlay 
          muted 
          loop 
          playsInline 
          className="w-full h-full object-cover grayscale opacity-40"
        >
          <source src="https://www.orfeoai.com/wp-content/uploads/2025/compressed.mp4" type="video/mp4" />
